parameters.jsCode:
const originalInput = $('Set - Prepare Execution Context').item.json;
const current = $input.item.json;

let aiOutput =
  current.output ||
  current.text ||
  current.message ||
  current.content ||
  current.data ||
  current;

if (typeof aiOutput === 'string') {
  aiOutput = aiOutput
    .replace(/```json/g, '')
    .replace(/```/g, '')
    .trim();

  try {
    aiOutput = JSON.parse(aiOutput);
  } catch (error) {
    aiOutput = {
      wf08_repository_update: {
        update_strategy: 'AI output could not be parsed as valid JSON.',
        target_branch: originalInput.branch || 'main',
        file_changes: [],
        test_files: [],
        commands_to_run: [],
        commit_message: '',
        pull_request_title: '',
        pull_request_description: '',
        repository_update_ready: false,
        human_validation_required: true
      }
    };
  }
}

const update = aiOutput.wf08_repository_update || aiOutput;

return {
  json: {
    ...originalInput,
    wf08_repository_update: {
      update_strategy: update.update_strategy || '',
      target_branch: update.target_branch || originalInput.branch || 'main',
      file_changes: Array.isArray(update.file_changes) ? update.file_changes : [],
      test_files: Array.isArray(update.test_files) ? update.test_files : [],
      commands_to_run: Array.isArray(update.commands_to_run) ? update.commands_to_run : [],
      commit_message: update.commit_message || '',
      pull_request_title: update.pull_request_title || '',
      pull_request_description: update.pull_request_description || '',
      repository_update_ready: Boolean(update.repository_update_ready),
      human_validation_required: true
    }
  }
};

